class V1ReleaseUpgradeConfiguration(BaseModel):
    avoid_pre_releases: bool | None = Field(None, description='Avoid prereleases.')
    no_upgrade_package_set: list[str] | None = Field(
        None, description='These packages can not be upgraded and will be skipped.'
    )
    prefer_minor_version_upgrades: bool | None = Field(
        None,
        description='Give higher priority to upgrades to versions with the same major version since these are more likely to be compatible.',
    )
    reachable_findings_only: bool | None = Field(
        None, description='Only consider reachable findings.'
    )
    score_improvement_threshold: int | None = Field(
        None, description='Score improvement to consider an upgrade.'
    )
    skip_test: bool | None = Field(
        None,
        description='If true, ignores all the direct dependencies that are marked as TEST/BUILD.',
    )
    target_dependency: str | None = Field(
        None, description='Only analyze this direct dependency and ignore the others.'
    )
    top_only: int | None = Field(
        None, description='Only show the top N dependency upgrades.'
    )
    upgrade_if_better_scores: bool | None = Field(
        None,
        description='Whether to consider a version upgrade just to improve the Endor scores or not.',
    )
    upgrade_if_operational_findings: str | None = Field(
        None,
        description='Whether to consider a version upgrade if the current version has only operational findings or not.',
    )
    upgrade_if_vulnerability_findings: str | None = Field(
        None,
        description='Whether to consider a version upgrade if the current version has vulnerability findings or not.',
    )
    use_cia: bool | None = Field(
        None, description='Whether using change impact analysis or not.'
    )


class V1ReleaseUpgradeStats(BaseModel):
    cia_invocations: int | None = Field(None, description='CIA Invocations.')
    compute_time: float | None = Field(None, description='Compute time.')
    data_load_time: float | None = Field(None, description='Data load time.')
    database_version_count: int | None = Field(
        None,
        description='The number of versions for direct dependencies we found in our database.',
    )
    dep_meta_count: int | None = Field(None, description='Dependency meta Count.')
    dep_uuids: int | None = Field(None, description='Dependency UUIDs.')
    direct_dependency_count: int | None = Field(
        None, description='Direct dependency count.'
    )
    direct_deps_count: int | None = Field(
        None, description='Direct cependencies count.'
    )
    direct_deps_package_count: int | None = Field(
        None, description='Direct dependencies package count.'
    )
    findings_after_filtering: int | None = Field(
        None, description='Findings after filtering.'
    )
    findings_fixed_by_upgrade_count: int | None = Field(
        None, description='Findings Fixed By Upgrade Count.'
    )
    findings_read: int | None = Field(None, description='Findings read.')
    incomplete_releases: int | None = Field(
        None, description='Releases not considered because of lack of information.'
    )
    max_releases_behind: int | None = Field(None, description='Max Releases Behind.')
    missing_version_count: int | None = Field(
        None,
        description='The number of direct dependency versions we miss from our database.',
    )
    namespace: str | None = Field(None, description='Namespace.')
    package_count: int | None = Field(None, description='Package Count.')
